mapper.select:
SELECT
FROM tb_csm_notice a LEFT JOIN tb_mbm_admin_user b ON a.create_id = b.id LEFT JOIN tb_mbm_admin_user c ON a.modified_id = c.id WHERE 1=1
ORDER BY a.id DESC LIMIT #{offset}, #{recordSize}

mapper.insert:

INSERT INTO tb_csm_notice (title, content, display_yn, top_yn, create_id, modified_id)
VALUES(#{title},
		#{content},
		#{displayYn},
		#{topYn},
		#{createId},
		#{modifiedId}
);
